('patient1@example.com', 'scrypt:32768:8:1$replace_with_generated_hash', 'Aarav Sharma', 'patient', 'patient-token-123'),
('patient2@example.com', 'scrypt:32768:8:1$replace_with_generated_hash', 'Meera Iyer', 'patient', 'patient-token-456'),
('doctor1@example.com', 'scrypt:32768:8:1$replace_with_generated_hash', 'Dr. Kavya Rao', 'doctor', 'doctor-token-123'),
('doctor2@example.com', 'scrypt:32768:8:1$replace_with_generated_hash', 'Dr. Arjun Menon', 'doctor', 'doctor-token-456');

INSERT INTO doctors (user_id, specialty, room_number)
VALUES
((SELECT id FROM users WHERE email = 'doctor1@example.com'), 'Cardiology', 'A101'),
((SELECT id FROM users WHERE email = 'doctor2@example.com'), 'Orthopedics', 'B205');

INSERT INTO appointments (
    patient_id,
    doctor_id,
    appointment_date,
    time_slot,
    queue_number,
    status
)
VALUES
(
    (SELECT id FROM users WHERE email = 'patient1@example.com'),
    (SELECT doctors.id FROM doctors JOIN users ON doctors.user_id = users.id WHERE users.email = 'doctor1@example.com'),
    CURDATE(),
    '10:00:00',
    1,
    'scheduled'
),
(
    (SELECT id FROM users WHERE email = 'patient2@example.com'),
    (SELECT doctors.id FROM doctors JOIN users ON doctors.user_id = users.id WHERE users.email = 'doctor1@example.com'),
    CURDATE(),
    '10:15:00',
    2,
    'scheduled'
);
